sql:
SELECT * 
FROM fatalities 
WHERE fatality_cause = 'storm surge';

SELECT storm_name
FROM storms
WHERE year_id < 2000;

external_knowledge:
- 'stormiest season' refers to the year with the highest number of storms;
- 'frequent were the tempests' means the count of storms in each year;
- 'stormy decade' is a metaphorical expression, implying an analysis over a span of years rather than literal decades.

sql:
SELECT year_name, total_damages, average_windspeed, average_pressure
FROM years
WHERE hu_count > 0;

SELECT "storm_name"
FROM "storms"
WHERE "windspeed" > (SELECT AVG("windspeed") FROM "storms");

SELECT storm_name
FROM storms
ORDER BY damages DESC;

external_knowledge:
- "tempestuous year" is a metaphorical expression referring to a year with many storms;
- "dominating forces" here refers to the storm categories that had the most occurrences;
- "rise to the surface like a tempestuous wave" is a metaphorical way to describe the occurrence of storms, implying their appearance and impact.

sql:
SELECT *
FROM years
WHERE hu_count > 2 * (SELECT AVG(hu_count) FROM years);

SELECT MAX(damage_amount) AS MaxDamage
FROM damages
WHERE damage_type = 'property' AND location = 'New York';

external_knowledge:
- "Monsters of the storm world" refers to the most powerful storms (those with the highest windspeed).; 
- "After the turn of the millennium" refers to storm occurrences after the year 2000.; 
- "Fury of the winds" represents the destructive power measured by windspeed.; 
- "Inevitable chaos" signifies the total damage and fatalities caused by the storms.; 
- "Devastation beyond a million dollars" indicates total damage exceeding $1,000,000.; 
- "Claiming the lives of more than five hundred souls" indicates total fatalities exceeding 500.

sql:
SELECT storm_name 
FROM storms 
WHERE storm_id = 0;

SELECT year_id, year_name, average_windspeed, average_pressure
FROM years
WHERE hu_count >= 1 AND average_pressure > 995.0;

SELECT storm_name, SUM(fatalities) AS total_casualties
FROM storms
GROUP BY storm_name;
